import React, { useState, useRef } from 'react';
import axios from 'axios';
import toast from 'react-hot-toast';
import { useAuth } from '../context/AuthContext';

export default function Navbar({ onNewPost }) {
  const { user, logout } = useAuth();
  const [showCreate, setShowCreate] = useState(false);
  const [showMenu, setShowMenu] = useState(false);
  const [caption, setCaption] = useState('');
  const [image, setImage] = useState(null);
  const [preview, setPreview] = useState(null);
  const [posting, setPosting] = useState(false);
  const fileRef = useRef();

  const handleFile = e => {
    const file = e.target.files[0];
    if (!file) return;
    setImage(file);
    setPreview(URL.createObjectURL(file));
  };

  const submitPost = async () => {
    if (!image && !caption.trim()) return toast.error('Add a photo or caption');
    setPosting(true);
    try {
      const fd = new FormData();
      fd.append('caption', caption);
      if (image) fd.append('image', image);
      const { data } = await axios.post('/api/posts', fd, {
        headers: { 'Content-Type': 'multipart/form-data' }
      });
      onNewPost(data);
      toast.success('Post shared! ✨');
      setShowCreate(false);
      setCaption('');
      setImage(null);
      setPreview(null);
    } catch {
      toast.error('Failed to post');
    } finally {
      setPosting(false);
    }
  };

  const closeCreate = () => {
    setShowCreate(false);
    setCaption('');
    setImage(null);
    setPreview(null);
  };

  const avatarUrl = user?.avatar ? `http://localhost:5000${user.avatar}` : null;
  const initials = (user?.username || 'U')[0].toUpperCase();

  return (
    <>
      <nav style={styles.nav}>
        <div style={styles.inner}>
          {/* Logo */}
          <div style={styles.logo}>Instagram</div>

          {/* Search */}
          <div style={styles.searchWrap}>
            <svg style={styles.searchIcon} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
              <circle cx="11" cy="11" r="8"/><path d="M21 21l-4.35-4.35"/>
            </svg>
            <input style={styles.searchInput} placeholder="Search" />
          </div>

          {/* Right Icons */}
          <div style={styles.right}>
            {/* Home */}
            <button style={styles.iconBtn} title="Home">
              <svg viewBox="0 0 24 24" width="24" height="24" fill="currentColor">
                <path d="M9.005 16.545a2.997 2.997 0 012.997-2.997A2.997 2.997 0 0115 16.545V22h7V11.543L12 2 2 11.543V22h7.005z"/>
              </svg>
            </button>

            {/* Create Post */}
            <button style={styles.iconBtn} title="Create" onClick={() => setShowCreate(true)}>
              <svg viewBox="0 0 24 24" width="24" height="24" fill="none" stroke="currentColor" strokeWidth="2">
                <rect x="3" y="3" width="18" height="18" rx="3"/>
                <path d="M12 8v8M8 12h8"/>
              </svg>
            </button>

            {/* Explore */}
            <button style={styles.iconBtn} title="Explore">
              <svg viewBox="0 0 24 24" width="24" height="24" fill="none" stroke="currentColor" strokeWidth="2">
                <circle cx="12" cy="12" r="10"/>
                <polygon points="16.24 7.76 14.12 14.12 7.76 16.24 9.88 9.88 16.24 7.76"/>
              </svg>
            </button>

            {/* Notifications */}
            <button style={styles.iconBtn} title="Notifications">
              <svg viewBox="0 0 24 24" width="24" height="24" fill="none" stroke="currentColor" strokeWidth="2">
                <path d="M20.84 4.61a5.5 5.5 0 00-7.78 0L12 5.67l-1.06-1.06a5.5 5.5 0 00-7.78 7.78l1.06 1.06L12 21.23l7.78-7.78 1.06-1.06a5.5 5.5 0 000-7.78z"/>
              </svg>
            </button>

            {/* Profile menu */}
            <div style={{ position: 'relative' }}>
              <button style={{ ...styles.iconBtn, padding: 0 }} onClick={() => setShowMenu(p => !p)}>
                {avatarUrl
                  ? <img src={avatarUrl} alt="avatar" style={{ width: 26, height: 26, borderRadius: '50%', objectFit: 'cover' }} />
                  : <div style={{ width: 26, height: 26, borderRadius: '50%', background: 'linear-gradient(135deg,#667eea,#764ba2)', display:'flex', alignItems:'center', justifyContent:'center', color:'#fff', fontSize:12, fontWeight:600 }}>{initials}</div>
                }
              </button>
              {showMenu && (
                <div style={styles.dropdown}>
                  <div style={styles.dropItem}>
                    <svg viewBox="0 0 24 24" width="18" height="18" fill="none" stroke="currentColor" strokeWidth="2"><circle cx="12" cy="8" r="4"/><path d="M4 20c0-4 3.6-7 8-7s8 3 8 7"/></svg>
                    <span>Profile (@{user?.username})</span>
                  </div>
                  <div style={styles.divider}/>
                  <div style={styles.dropItem} onClick={logout}>
                    <svg viewBox="0 0 24 24" width="18" height="18" fill="none" stroke="currentColor" strokeWidth="2"><path d="M9 21H5a2 2 0 01-2-2V5a2 2 0 012-2h4M16 17l5-5-5-5M21 12H9"/></svg>
                    <span>Log Out</span>
                  </div>
                </div>
              )}
            </div>
          </div>
        </div>
      </nav>

      {/* Create Post Modal */}
      {showCreate && (
        <div style={styles.overlay} onClick={e => e.target === e.currentTarget && closeCreate()}>
          <div style={styles.modal}>
            <div style={styles.modalHeader}>
              <span style={{ fontSize: 16, fontWeight: 600 }}>Create new post</span>
              <button onClick={closeCreate} style={{ fontSize: 24, lineHeight: 1, color: '#262626' }}>×</button>
            </div>

            {!preview ? (
              <div style={styles.uploadArea} onClick={() => fileRef.current.click()}>
                <svg viewBox="0 0 24 24" width="64" height="64" fill="none" stroke="#262626" strokeWidth="1.5">
                  <rect x="3" y="3" width="18" height="18" rx="2"/>
                  <circle cx="8.5" cy="8.5" r="1.5"/>
                  <polyline points="21 15 16 10 5 21"/>
                </svg>
                <p style={{ marginTop: 16, fontSize: 20, color: '#262626' }}>Drag photos and videos here</p>
                <button style={styles.selectBtn} type="button">Select from computer</button>
                <input ref={fileRef} type="file" accept="image/*" style={{ display: 'none' }} onChange={handleFile} />
              </div>
            ) : (
              <div style={styles.postEditor}>
                <img src={preview} alt="preview" style={styles.previewImg} />
                <div style={styles.captionArea}>
                  <div style={{ display: 'flex', alignItems: 'center', gap: 8, marginBottom: 12 }}>
                    {avatarUrl
                      ? <img src={avatarUrl} alt="" style={{ width: 32, height: 32, borderRadius: '50%', objectFit: 'cover' }} />
                      : <div style={{ width:32, height:32, borderRadius:'50%', background:'linear-gradient(135deg,#667eea,#764ba2)', display:'flex', alignItems:'center', justifyContent:'center', color:'#fff', fontSize:13, fontWeight:600 }}>{initials}</div>
                    }
                    <span style={{ fontWeight: 600, fontSize: 14 }}>{user?.username}</span>
                  </div>
                  <textarea
                    value={caption}
                    onChange={e => setCaption(e.target.value)}
                    placeholder="Write a caption..."
                    style={styles.captionInput}
                    maxLength={2200}
                  />
                  <div style={{ fontSize: 12, color: '#8e8e8e', textAlign: 'right' }}>{caption.length}/2,200</div>
                  <button onClick={submitPost} style={{ ...styles.shareBtn, opacity: posting ? 0.7 : 1 }} disabled={posting}>
                    {posting ? 'Sharing...' : 'Share'}
                  </button>
                </div>
              </div>
            )}
          </div>
        </div>
      )}
    </>
  );
}

const styles = {
  nav: { position: 'fixed', top: 0, left: 0, right: 0, background: '#fff', borderBottom: '1px solid #dbdbdb', zIndex: 1000, height: 60 },
  inner: { maxWidth: 975, margin: '0 auto', height: '100%', display: 'flex', alignItems: 'center', justifyContent: 'space-between', padding: '0 20px' },
  logo: { fontFamily: "'Grand Hotel', cursive", fontSize: 28, color: '#262626', cursor: 'pointer' },
  searchWrap: { position: 'relative', flex: '0 1 268px' },
  searchIcon: { position: 'absolute', left: 12, top: '50%', transform: 'translateY(-50%)', width: 16, height: 16, color: '#8e8e8e' },
  searchInput: { width: '100%', padding: '8px 8px 8px 36px', background: '#efefef', border: 'none', borderRadius: 8, fontSize: 14, outline: 'none' },
  right: { display: 'flex', alignItems: 'center', gap: 8 },
  iconBtn: { display: 'flex', alignItems: 'center', justifyContent: 'center', width: 40, height: 40, borderRadius: '50%', color: '#262626', transition: 'background .2s', cursor: 'pointer', border: 'none', background: 'none' },
  dropdown: { position: 'absolute', right: 0, top: '100%', background: '#fff', border: '1px solid #dbdbdb', borderRadius: 8, boxShadow: '0 4px 16px rgba(0,0,0,.12)', minWidth: 200, zIndex: 100, overflow: 'hidden', marginTop: 8 },
  dropItem: { display: 'flex', alignItems: 'center', gap: 10, padding: '12px 16px', cursor: 'pointer', fontSize: 14, transition: 'background .15s' },
  divider: { height: 1, background: '#efefef', margin: '4px 0' },
  overlay: { position: 'fixed', inset: 0, background: 'rgba(0,0,0,.65)', zIndex: 2000, display: 'flex', alignItems: 'center', justifyContent: 'center' },
  modal: { background: '#fff', borderRadius: 12, overflow: 'hidden', width: '90vw', maxWidth: 855, maxHeight: '90vh', display: 'flex', flexDirection: 'column' },
  modalHeader: { display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '14px 16px', borderBottom: '1px solid #dbdbdb' },
  uploadArea: { display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', padding: '60px 20px', cursor: 'pointer', minHeight: 400 },
  selectBtn: { marginTop: 20, background: '#0095f6', color: '#fff', border: 'none', borderRadius: 8, padding: '8px 20px', fontWeight: 700, cursor: 'pointer', fontSize: 14 },
  postEditor: { display: 'flex', flex: 1, minHeight: 400 },
  previewImg: { width: 500, height: 450, objectFit: 'cover', borderRight: '1px solid #dbdbdb', flexShrink: 0 },
  captionArea: { flex: 1, padding: 16, display: 'flex', flexDirection: 'column' },
  captionInput: { width: '100%', flex: 1, border: 'none', outline: 'none', resize: 'none', fontSize: 14, lineHeight: 1.6, minHeight: 200 },
  shareBtn: { background: '#0095f6', color: '#fff', border: 'none', borderRadius: 8, padding: '8px 20px', fontWeight: 700, cursor: 'pointer', fontSize: 14, marginTop: 12, alignSelf: 'flex-end' },
};
